  1	import * as React from 'react';
  2	import { useExistingFileSystemNames } from '@odf/core/components/create-storage-system/external-systems/common/useResourceNameValidation';
  3	import {
  4	  PageHeading,
  5	  useCustomTranslation,
  6	  TextInputWithFieldRequirements,
  7	  ButtonBar,
  8	} from '@odf/shared';
  9	import { ValidatedPasswordInput } from '@odf/shared/text-inputs/password-input';
 10	import * as _ from 'lodash-es';
 11	import { useNavigate } from 'react-router-dom-v5-compat';
 12	import {
 13	  Form,
 14	  FormGroup,
 15	  FormSection,
 16	  Grid,
 17	  GridItem,
 18	  FileUpload,
 19	  Checkbox,
 20	  ActionGroup,
 21	  Button,
 22	  Alert,
 23	  FormHelperText,
 24	  HelperText,
 25	  HelperTextItem,
 26	  AlertVariant,
 27	  ButtonType,
 28	  ButtonVariant,
 29	} from '@patternfly/react-core';
 30	import { useIsLocalClusterConfigured } from '../common/hooks';
 31	import { NodesSection } from '../common/NodesSection';
 32	import {
 33	  configureMetricsNamespaceLabels,
 34	  createScaleLocalClusterPayload,
 35	  labelNodes,
 36	} from '../common/payload';
 37	import {
 38	  createScaleCaCertSecretPayload,
 39	  createScaleRemoteClusterPayload,
 40	  createFileSystem,
 41	  createConfigMapPayload,
 42	  createEncryptionConfigPayload,
 43	  createUserDetailsSecretPayload,
 44	} from './payload';
 45	import { ScaleSystemComponentState, initialComponentState } from './types';
 46	import useScaleSystemFormValidation from './useFormValidation';
 47	import './CreateScaleSystem.scss';
 48	
 49	type CreateScaleSystemFormProps = {
 50	  componentState: ScaleSystemComponentState;
 51	  setComponentState: React.Dispatch<
 52	    React.SetStateAction<ScaleSystemComponentState>
 53	  >;
 54	};
 55	
 56	const CreateScaleSystemForm: React.FC<CreateScaleSystemFormProps> = ({
 57	  componentState,
 58	  setComponentState,
 59	}) => {
 60	  const { t } = useCustomTranslation();
 61	  const [generalCAFileName, setGeneralCAFileName] = React.useState('');
 62	  const [encryptionCAFileName, setEncryptionCAFileName] = React.useState('');
 63	  const navigate = useNavigate();
 64	  const [error, setError] = React.useState<string>('');
 65	  const [loading, setLoading] = React.useState(false);
 66	  const localCluster = useIsLocalClusterConfigured();
 67	  const isLocalClusterConfigured = !_.isEmpty(localCluster);
 68	
 69	  const existingFileSystemNames = useExistingFileSystemNames();
 70	
 71	  const {
 72	    fieldRequirements,
 73	    control,
 74	    handleSubmit,
 75	    formState: { isSubmitted },
 76	    watch,
 77	    getValues,
 78	  } = useScaleSystemFormValidation(existingFileSystemNames);
 79	
 80	  // Watch only specific fields instead of all form values to prevent excessive re-renders
 81	  const name = watch('name');
 82	  const mandatoryHost = watch('mandatory-endpoint-host');
 83	  const mandatoryPort = watch('mandatory-endpoint-port');
 84	  const userName = watch('userName');
 85	  const password = watch('password');
 86	  const fileSystemName = watch('fileSystemName');
 87	  const encryptionUserName = watch('encryptionUserName');
 88	  const encryptionPassword = watch('encryptionPassword');
 89	  const encryptionPort = watch('encryptionPort');
 90	  const client = watch('client');
 91	  const remoteRKM = watch('remoteRKM');
 92	  const serverInformation = watch('serverInformation');
 93	  const tenantId = watch('tenantId');
 94	
 95	  const mandatoryFieldsValid = !!(
 96	    name &&
 97	    mandatoryHost &&
 98	    mandatoryPort &&
 99	    userName &&
100	    password &&
101	    fileSystemName &&
102	    componentState.selectedNodes.length > 0
103	  );
104	
105	  const encryptionFieldsValid =
106	    !componentState.encryptionEnabled ||
107	    !!(
108	      encryptionUserName &&
109	      encryptionPassword &&
110	      encryptionPort &&
111	      client &&
112	      remoteRKM &&
113	      serverInformation &&
114	      tenantId
115	    );
116	
117	  const isFormValid = mandatoryFieldsValid && encryptionFieldsValid;
118	
119	  const handleGeneralCAFileInputChange = React.useCallback(
120	    (_ev, file: File) => {
121	      setGeneralCAFileName(file.name);
122	      const reader = new FileReader();
123	      reader.onload = (e) => {
124	        const result = e.target?.result as string;
125	        // Convert the file content to base64
126	        const base64Content = btoa(result);
127	        setComponentState((prev) => ({
128	          ...prev,
129	          caCertificate: base64Content,
130	        }));
131	      };
132	      reader.readAsText(file);
133	    },
134	    [setComponentState]
135	  );
136	
137	  const handleEncryptionCAFileInputChange = React.useCallback(
138	    (_ev, file: File) => {
139	      setEncryptionCAFileName(file.name);
140	      const reader = new FileReader();
141	      reader.onload = (e) => {
142	        const result = e.target?.result as string;
143	        // Convert the file content to base64
144	        const base64Content = btoa(result);
145	        setComponentState((prev) => ({
146	          ...prev,
147	          encryptionCert: base64Content,
148	        }));
149	      };
150	      reader.readAsText(file);
151	    },
152	    [setComponentState]
153	  );
154	
155	  const onCreate = React.useCallback(async () => {
156	    setLoading(true);
157	    setError('');
158	
159	    try {
160	      const formData = getValues();
161	      const patchNodes = labelNodes(componentState.selectedNodes);
162	      if (!isLocalClusterConfigured) {
163	        await patchNodes();
164	        const localClusterPromise = createScaleLocalClusterPayload();
165	        await localClusterPromise();
166	        await configureMetricsNamespaceLabels();
167	      }
168	      const secretPromise = createScaleCaCertSecretPayload(
169	        formData.name,
170	        componentState.caCertificate
171	      );
172	      const userDetailsSecretName = `${formData.name}-user-details-secret`;
173	      const userDetailsSecretPromise = createUserDetailsSecretPayload(
174	        userDetailsSecretName,
175	        formData.userName,
176	        formData.password
177	      );
178	      const endpointHostNames = [
179	        formData['mandatory-endpoint-host'],
180	        ...(formData['optional-endpoint-1-host']
181	          ? [formData['optional-endpoint-1-host']]
182	          : []),
183	        ...(formData['optional-endpoint-2-host']
184	          ? [formData['optional-endpoint-2-host']]
185	          : []),
186	      ];
187	      const remoteClusterCaCert = `${formData.name}-ca-cert`;
188	      const remoteClusterConfigMapPromise = createConfigMapPayload(
189	        remoteClusterCaCert,
190	        {
191	          'ca.crt': componentState.caCertificate,
192	        }
193	      );
194	      const remoteClusterPromise = createScaleRemoteClusterPayload(
195	        formData.name,
196	        endpointHostNames,
197	        formData['mandatory-endpoint-port'],
198	        userDetailsSecretName,
199	        componentState.caCertificate ? remoteClusterCaCert : undefined
200	      );
201	      const encryptionSecretName = `${formData.name}-encryption-secret`;
202	      const encryptionSecretPromise = createUserDetailsSecretPayload(
203	        encryptionSecretName,
204	        formData.encryptionUserName,
205	        formData.encryptionPassword
206	      );
207	      const encryptionConfigMapName = `${formData.name}-encryption-config`;
208	      const encryptionConfigMapPromise = createConfigMapPayload(
209	        encryptionConfigMapName,
210	        {
211	          'enc-ca.crt': componentState.encryptionCert,
212	        }
213	      );
214	      const encryptionConfigPromise = createEncryptionConfigPayload(
215	        `${formData.name}-encryption-config`,
216	        formData.serverInformation,
217	        formData.tenantId,
218	        formData.client,
219	        formData.encryptionPassword,
220	        encryptionConfigMapName
221	      );
222	      const fileSystemPromise = createFileSystem(
223	        formData.name,
224	        formData.fileSystemName
225	      );
226	
227	      if (componentState.caCertificate) {
228	        await secretPromise();
229	      }
230	      await userDetailsSecretPromise();
231	      if (componentState.caCertificate) {
232	        await remoteClusterConfigMapPromise();
233	      }
234	      await remoteClusterPromise();
235	      await fileSystemPromise();
236	      if (componentState.encryptionEnabled) {
237	        await encryptionConfigMapPromise();
238	        await encryptionSecretPromise();
239	        await encryptionConfigPromise();
240	      }
241	      navigate(
242	        `/odf/external-systems/scale.spectrum.ibm.com~v1beta1~remotecluster/${formData.name}`
243	      );
244	    } catch (err) {
245	      setError(err.message);
246	    } finally {
247	      setLoading(false);
248	    }
249	  }, [
250	    componentState.caCertificate,
251	    componentState.encryptionCert,
252	    componentState.encryptionEnabled,
253	    componentState.selectedNodes,
254	    getValues,
255	    isLocalClusterConfigured,
256	    navigate,
257	  ]);
258	
259	  return (
260	    <Form onSubmit={handleSubmit(onCreate)} isWidthLimited>
261	      <FormSection title={t('General configuration')}>
262	        <TextInputWithFieldRequirements
263	          control={control}
264	          fieldRequirements={fieldRequirements.name}
265	          popoverProps={{
266	            headerContent: t('Name requirements'),
267	            footerContent: `${t('Example')}: my-scale-system`,
268	          }}
269	          formGroupProps={{
270	            label: t('Name'),
271	            fieldId: 'name',
272	            isRequired: true,
273	          }}
274	          textInputProps={{
275	            id: 'name',
276	            name: 'name',
277	            type: 'text',
278	            placeholder: t('Enter a name for the external system'),
279	            'data-test': 'scale-system-name',
280	          }}
281	          helperText={t(
282	            'A unique connection name to identify this external system in Data Foundation.'
283	          )}
284	        />
285	        <FormGroup label={t('Select local cluster nodes')} isRequired>
286	          <NodesSection
287	            isDisabled={isLocalClusterConfigured}
288	            selectedNodes={componentState.selectedNodes}
289	            setSelectedNodes={(nodes) =>
290	              setComponentState((prev) => ({ ...prev, selectedNodes: nodes }))
291	            }
292	          />
293	        </FormGroup>
294	      </FormSection>
295	      <FormSection title={t('Connection details')}>
296	        <FormHelperText>
297	          <HelperText>
298	            <HelperTextItem>
299	              {t(
300	                'Enter at least one IBM Scale management endpoint to authenticate and configure the remote cluster (For high availability, define 2 or more endpoints). Use valid credentials to verify and establish a connection to the remote cluster.'
301	              )}
302	            </HelperTextItem>
303	          </HelperText>
304	        </FormHelperText>
305	        <Grid hasGutter>
306	          <GridItem span={6}>
307	            <TextInputWithFieldRequirements
308	              control={control}
309	              fieldRequirements={fieldRequirements.hostname}
310	              popoverProps={{
311	                headerContent: t('Hostname requirements'),
312	                footerContent: `${t('Example')}: hostname.example.com`,
313	              }}
314	              formGroupProps={{
315	                label: t('Management endpoints'),
316	                fieldId: 'mandatory-endpoint-host',
317	                isRequired: true,
318	              }}
319	              textInputProps={{
320	                id: 'mandatory-endpoint-host',
321	                name: 'mandatory-endpoint-host',
322	                type: 'text',
323	                placeholder: t('Mandatory (e.g hostname.example.com)'),
324	                'data-test': 'mandatory-endpoint-host',
325	              }}
326	            />
327	          </GridItem>
328	          <GridItem span={6}>
329	            <TextInputWithFieldRequirements
330	              control={control}
331	              fieldRequirements={fieldRequirements.port}
332	              popoverProps={{
333	                headerContent: t('Port requirements'),
334	                footerContent: `${t('Example')}: 8843`,
335	              }}
336	              formGroupProps={{
337	                label: t('Port'),
338	                fieldId: 'mandatory-endpoint-port',
339	                isRequired: true,
340	              }}
341	              textInputProps={{
342	                id: 'mandatory-endpoint-port',
343	                name: 'mandatory-endpoint-port',
344	                type: 'text',
345	                placeholder: t('Mandatory (e.g 8843)'),
346	                'data-test': 'mandatory-endpoint-port',
347	              }}
348	            />
349	          </GridItem>
350	          <GridItem span={6}>
351	            <TextInputWithFieldRequirements
352	              control={control}
353	              fieldRequirements={fieldRequirements.hostname}
354	              popoverProps={{
355	                headerContent: t('Hostname requirements'),
356	                footerContent: `${t('Example')}: hostname.example.com`,
357	              }}
358	              formGroupProps={{
359	                label: t('Optional endpoint 1'),
360	                fieldId: 'optional-endpoint-1-host',
361	              }}
362	              textInputProps={{
363	                id: 'optional-endpoint-1-host',
364	                name: 'optional-endpoint-1-host',
365	                type: 'text',
366	                placeholder: t('Optional (e.g hostname.example.com)'),
367	                'data-test': 'optional-endpoint-1-host',
368	              }}
369	            />
370	          </GridItem>
371	          <GridItem span={6}>
372	            <TextInputWithFieldRequirements
373	              control={control}
374	              fieldRequirements={fieldRequirements.port}
375	              popoverProps={{
376	                headerContent: t('Port requirements'),
377	                footerContent: `${t('Example')}: 8843`,
378	              }}
379	              formGroupProps={{
380	                label: t('Optional port 1'),
381	                fieldId: 'optional-endpoint-1-port',
382	              }}
383	              textInputProps={{
384	                id: 'optional-endpoint-1-port',
385	                name: 'optional-endpoint-1-port',
386	                type: 'text',
387	                placeholder: t('Optional (e.g 8843)'),
388	                'data-test': 'optional-endpoint-1-port',
389	              }}
390	            />
391	          </GridItem>
392	          <GridItem span={6}>
393	            <TextInputWithFieldRequirements
394	              control={control}
395	              fieldRequirements={fieldRequirements.hostname}
396	              popoverProps={{
397	                headerContent: t('Hostname requirements'),
398	                footerContent: `${t('Example')}: hostname.example.com`,
399	              }}
400	              formGroupProps={{
401	                label: t('Optional endpoint 2'),
402	                fieldId: 'optional-endpoint-2-host',
403	              }}
404	              textInputProps={{
405	                id: 'optional-endpoint-2-host',
406	                name: 'optional-endpoint-2-host',
407	                type: 'text',
408	                placeholder: t('Optional (e.g hostname.example.com)'),
409	                'data-test': 'optional-endpoint-2-host',
410	              }}
411	            />
412	          </GridItem>
413	          <GridItem span={6}>
414	            <TextInputWithFieldRequirements
415	              control={control}
416	              fieldRequirements={fieldRequirements.port}
417	              popoverProps={{
418	                headerContent: t('Port requirements'),
419	                footerContent: `${t('Example')}: 8843`,
420	              }}
421	              formGroupProps={{
422	                label: t('Optional port 2'),
423	                fieldId: 'optional-endpoint-2-port',
424	              }}
425	              textInputProps={{
426	                id: 'optional-endpoint-2-port',
427	                name: 'optional-endpoint-2-port',
428	                type: 'text',
429	                placeholder: t('Optional (e.g 8843)'),
430	                'data-test': 'optional-endpoint-2-port',
431	              }}
432	            />
433	          </GridItem>
434	        </Grid>
435	        <TextInputWithFieldRequirements
436	          control={control}
437	          fieldRequirements={fieldRequirements.username}
438	          popoverProps={{
439	            headerContent: t('Username requirements'),
440	            footerContent: `${t('Example')}: admin`,
441	          }}
442	          formGroupProps={{
443	            label: t('User name'),
444	            fieldId: 'userName',
445	            isRequired: true,
446	          }}
447	          textInputProps={{
448	            id: 'userName',
449	            name: 'userName',
450	            type: 'text',
451	            placeholder: t('Enter username'),
452	            'data-test': 'username',
453	          }}
454	        />
455	        <ValidatedPasswordInput
456	          control={control}
457	          fieldRequirements={fieldRequirements.password}
458	          popoverProps={{
459	            headerContent: t('Password requirements'),
460	            footerContent: `${t('Example')}: mypassword123`,
461	          }}
462	          formGroupProps={{
463	            label: t('Password'),
464	            fieldId: 'password',
465	            isRequired: true,
466	          }}
467	          textInputProps={{
468	            id: 'password',
469	            name: 'password',
470	            placeholder: t('Enter password'),
471	            'data-test': 'password',
472	          }}
473	          helperText={t('Password is required')}
474	        />
475	        <FormGroup label={t('CA certificate')}>
476	          <FileUpload
477	            placeholder={t('Upload CA certificate')}
478	            id="file-upload"
479	            value={componentState.caCertificate}
480	            filename={generalCAFileName}
481	            onClearClick={() => {
482	              setGeneralCAFileName('');
483	              setComponentState((prev) => ({ ...prev, caCertificate: '' }));
484	            }}
485	            onFileInputChange={handleGeneralCAFileInputChange}
486	          />
487	          <FormHelperText>
488	            <HelperText>
489	              <HelperTextItem>
490	                {t('Upload a certificate to secure your configuration.')}
491	              </HelperTextItem>
492	            </HelperText>
493	          </FormHelperText>
494	        </FormGroup>
495	      </FormSection>
496	      <FormSection title={t('File system configuration')}>
497	        <FormHelperText>
498	          <HelperText>
499	            <HelperTextItem>
500	              {t('Specify the remote file system to access on this cluster.')}
501	            </HelperTextItem>
502	          </HelperText>
503	        </FormHelperText>
504	        <TextInputWithFieldRequirements
505	          control={control}
506	          fieldRequirements={fieldRequirements.fileSystemName}
507	          popoverProps={{
508	            headerContent: t('File system name requirements'),
509	            footerContent: `${t('Example')}: my-filesystem`,
510	          }}
511	          formGroupProps={{
512	            label: t('File system name'),
513	            fieldId: 'fileSystemName',
514	            isRequired: true,
515	          }}
516	          textInputProps={{
517	            id: 'fileSystemName',
518	            name: 'fileSystemName',
519	            type: 'text',
520	            placeholder: t('Enter the file system name'),
521	            'data-test': 'file-system-name',
522	          }}
523	        />
524	        <FormGroup>
525	          <Checkbox
526	            id="encryption-enabled"
527	            label={t('Enable data encryption')}
528	            isChecked={componentState.encryptionEnabled}
529	            onChange={(_ev, checked) =>
530	              setComponentState((prev) => ({
531	                ...prev,
532	                encryptionEnabled: checked,
533	              }))
534	            }
535	            description={t(
536	              'Ensures all filesystem data is securely stored and protected.'
537	            )}
538	          />
539	        </FormGroup>
540	        {componentState.encryptionEnabled && (
541	          <>
542	            <TextInputWithFieldRequirements
543	              control={control}
544	              fieldRequirements={fieldRequirements.username}
545	              popoverProps={{
546	                headerContent: t('Encryption username requirements'),
547	                footerContent: `${t('Example')}: encryption-user`,
548	              }}
549	              formGroupProps={{
550	                label: t('Username'),
551	                fieldId: 'encryptionUserName',
552	                isRequired: true,
553	              }}
554	              textInputProps={{
555	                id: 'encryptionUserName',
556	                name: 'encryptionUserName',
557	                type: 'text',
558	                placeholder: t('Enter username'),
559	                'data-test': 'encryption-username',
560	              }}
561	            />
562	            <ValidatedPasswordInput
563	              control={control}
564	              fieldRequirements={fieldRequirements.password}
565	              popoverProps={{
566	                headerContent: t('Encryption password requirements'),
567	                footerContent: `${t('Example')}: mypassword123`,
568	              }}
569	              formGroupProps={{
570	                label: t('Password'),
571	                fieldId: 'encryptionPassword',
572	                isRequired: true,
573	              }}
574	              textInputProps={{
575	                id: 'encryptionPassword',
576	                name: 'encryptionPassword',
577	                placeholder: t('Enter password'),
578	                'data-test': 'encryption-password',
579	              }}
580	              helperText={t('Password is required')}
581	            />
582	            <TextInputWithFieldRequirements
583	              control={control}
584	              fieldRequirements={fieldRequirements.port}
585	              popoverProps={{
586	                headerContent: t('Port requirements'),
587	                footerContent: `${t('Example')}: 443`,
588	              }}
589	              formGroupProps={{
590	                label: t('Port'),
591	                fieldId: 'encryptionPort',
592	                isRequired: true,
593	              }}
594	              textInputProps={{
595	                id: 'encryptionPort',
596	                name: 'encryptionPort',
597	                type: 'text',
598	                placeholder: t('Enter port'),
599	                'data-test': 'encryption-port',
600	              }}
601	            />
602	            <TextInputWithFieldRequirements
603	              control={control}
604	              fieldRequirements={fieldRequirements.client}
605	              popoverProps={{
606	                headerContent: t('Client requirements'),
607	                footerContent: `${t('Example')}: my-client`,
608	              }}
609	              formGroupProps={{
610	                label: t('Client'),
611	                fieldId: 'client',
612	                isRequired: true,
613	              }}
614	              textInputProps={{
615	                id: 'client',
616	                name: 'client',
617	                type: 'text',
618	                placeholder: t('Enter client'),
619	                'data-test': 'client',
620	              }}
621	            />
622	            <TextInputWithFieldRequirements
623	              control={control}
624	              fieldRequirements={fieldRequirements.hostname}
625	              popoverProps={{
626	                headerContent: t('Remote RKM requirements'),
627	                footerContent: `${t('Example')}: rkm.example.com`,
628	              }}
629	              formGroupProps={{
630	                label: t('Remote RKM'),
631	                fieldId: 'remoteRKM',
632	                isRequired: true,
633	              }}
634	              textInputProps={{
635	                id: 'remoteRKM',
636	                name: 'remoteRKM',
637	                type: 'text',
638	                placeholder: t('Enter remote RKM'),
639	                'data-test': 'remote-rkm',
640	              }}
641	            />
642	            <FormGroup label={t('Encryption CA certificate')} isRequired>
643	              <FileUpload
644	                placeholder={t('Upload encryption CA certificate')}
645	                id="file-upload"
646	                value={componentState.encryptionCert}
647	                filename={encryptionCAFileName}
648	                onFileInputChange={handleEncryptionCAFileInputChange}
649	                onClearClick={() => {
650	                  setEncryptionCAFileName('');
651	                  setComponentState((prev) => ({
652	                    ...prev,
653	                    encryptionCert: '',
654	                  }));
655	                }}
656	              />
657	            </FormGroup>
658	            <TextInputWithFieldRequirements
659	              control={control}
660	              fieldRequirements={fieldRequirements.serverInfo}
661	              popoverProps={{
662	                headerContent: t('Server information requirements'),
663	                footerContent: `${t('Example')}: server.example.com:443`,
664	              }}
665	              formGroupProps={{
666	                label: t('Server information'),
667	                fieldId: 'serverInformation',
668	                isRequired: true,
669	              }}
670	              textInputProps={{
671	                id: 'serverInformation',
672	                name: 'serverInformation',
673	                type: 'text',
674	                placeholder: t('Enter server information'),
675	                'data-test': 'server-information',
676	              }}
677	            />
678	            <TextInputWithFieldRequirements
679	              control={control}
680	              fieldRequirements={fieldRequirements.tenantId}
681	              popoverProps={{
682	                headerContent: t('Tenant ID requirements'),
683	                footerContent: `${t('Example')}: tenant-123`,
684	              }}
685	              formGroupProps={{
686	                label: t('Tenant ID'),
687	                fieldId: 'tenantId',
688	                isRequired: true,
689	              }}
690	              textInputProps={{
691	                id: 'tenantId',
692	                name: 'tenantId',
693	                type: 'text',
694	                placeholder: t('Enter tenant ID'),
695	                'data-test': 'tenant-id',
696	              }}
697	            />
698	          </>
699	        )}
700	      </FormSection>
701	      {!isFormValid && isSubmitted && (
702	        <Alert
703	          variant={AlertVariant.danger}
704	          isInline
705	          title={t('Address form errors to proceed')}
706	        />
707	      )}
708	      {error && (
709	        <Alert variant="danger" title={t('Error')} isInline>
710	          {error}
711	        </Alert>
